export const 入山符乙一 = (bi) => {
    const u = bi.u;
    const k = 1.1;
    const X = (c) => (c - 12) * k;
    const Z = (r) => (r - 1.2) * k;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 星 = (c, r, 半 = 0.5) => bi.dot(X(c), Z(r), 半);
    // 頂點列四
    星(8.6, 3.9);
    星(11.6, 3.85);
    星(14.6, 3.8);
    星(17.4, 3.75);
    // 曲箱：弧脅外張
    線(p => p.M(X(8.4), Z(4.9)).C(X(9.2), Z(5.5), X(11.0), Z(5.7), X(13.0), Z(5.6))
        .C(X(15.0), Z(5.5), X(16.8), Z(5.3), X(17.8), Z(4.7)), 0.6);
    線(p => p.M(X(8.5), Z(5.2)).C(X(8.9), Z(7.3), X(8.9), Z(9.1), X(7.5), Z(11.0)), 0.6);
    線(p => p.M(X(17.7), Z(4.9)).C(X(17.4), Z(6.9), X(17.5), Z(8.9), X(18.4), Z(10.9)), 0.6);
    線(p => p.M(X(7.5), Z(11.05)).L(X(18.4), Z(10.95)), 0.6);
    // 內雙弧夾中構
    線(p => p.M(X(10.4), Z(5.5)).C(X(10.1), Z(7.4), X(10.0), Z(9.2), X(10.0), Z(10.9)));
    線(p => p.M(X(15.9), Z(5.3)).C(X(16.1), Z(7.2), X(16.2), Z(9.0), X(16.2), Z(10.8)));
    線(p => p.M(X(10.4), Z(6.9)).L(X(16.0), Z(6.8)));
    線(p => p.M(X(10.4), Z(8.55)).L(X(16.0), Z(8.45)));
    線(p => p.M(X(13.1), Z(5.3)).L(X(13.05), Z(8.5)));
    // 底角雙點
    星(7.4, 11.25, 0.55);
    星(18.4, 11.15, 0.55);
    // 右貫豎（綴三點直落符底）
    線(p => p.M(X(18.42), Z(11.4)).C(X(18.5), Z(18.0), X(18.4), Z(25.0), X(18.32), Z(32.2)), 0.6);
    星(18.4, 21.2, 0.55);
    星(18.3, 32.4, 0.6);
    // 中點・橫桁（左端點起）・雙點
    星(11.9, 12.6, 0.55);
    星(7.1, 14.0, 0.5);
    線(p => p.M(X(7.6), Z(14.05)).L(X(16.3), Z(13.85)), 0.42);
    星(9.7, 15.15, 0.6);
    星(12.7, 15.05, 0.6);
    // 雙弧＋右括曲
    線(p => p.M(X(7.6), Z(16.7)).C(X(9.6), Z(17.6), X(11.9), Z(17.4), X(13.7), Z(16.4)), 0.6);
    線(p => p.M(X(7.0), Z(18.2)).C(X(8.9), Z(19.0), X(11.2), Z(18.8), X(12.9), Z(17.8)), 0.6);
    出(p => p.M(X(13.9), Z(15.7)).C(X(14.5), Z(16.8), X(14.6), Z(17.9), X(14.3), Z(18.9)));
    // 左尸疊塔
    線(p => p.M(X(8.0), Z(19.8)).L(X(12.4), Z(19.6)), 0.6);
    出(p => p.M(X(8.0), Z(19.9)).C(X(7.2), Z(23.2), X(6.9), Z(27.0), X(5.6), Z(31.4)), 0.65);
    for (const z of [20.9, 22.2, 23.5, 24.8])
        線(p => p.M(X(8.5), Z(z + 0.5)).C(X(9.8), Z(z + 0.9), X(11.2), Z(z + 0.5), X(12.3), Z(z)));
    // 匚山箱
    線(p => p.M(X(8.8), Z(25.8)).L(X(8.8), Z(28.7)));
    線(p => p.M(X(8.8), Z(25.85)).L(X(12.4), Z(25.65)));
    線(p => p.M(X(10.3), Z(26.6)).L(X(10.25), Z(28.5)));
    線(p => p.M(X(9.4), Z(27.4)).L(X(11.7), Z(27.25)));
    線(p => p.M(X(11.8), Z(26.5)).L(X(11.75), Z(28.4)));
    線(p => p.M(X(8.8), Z(28.7)).L(X(12.5), Z(28.5)));
    // 內撇貫底
    出(p => p.M(X(12.6), Z(20.0)).C(X(11.4), Z(24.5), X(10.6), Z(28.6), X(9.7), Z(32.6)), 0.6);
    // 右王目乚柱
    線(p => p.M(X(12.6), Z(19.45)).L(X(16.7), Z(19.25)), 0.6);
    線(p => p.M(X(14.9), Z(20.3)).L(X(14.85), Z(22.65)));
    for (const z of [20.45, 21.5, 22.6])
        線(p => p.M(X(13.7), Z(z)).L(X(16.3), Z(z - 0.15)));
    // 目雙箱
    線(p => p.M(X(13.6), Z(23.35)).L(X(13.55), Z(26.2)));
    線(p => p.M(X(16.8), Z(23.25)).L(X(16.75), Z(26.1)));
    線(p => p.M(X(14.9), Z(23.4)).L(X(14.85), Z(26.15)));
    for (const z of [23.4, 24.3, 25.2, 26.15])
        線(p => p.M(X(13.6), Z(z)).L(X(16.8), Z(z - 0.12)));
    // 口箱
    線(p => p.M(X(14.0), Z(26.85)).L(X(13.95), Z(28.65)));
    線(p => p.M(X(14.0), Z(26.9)).L(X(16.5), Z(26.75)).L(X(16.45), Z(28.55)));
    線(p => p.M(X(14.0), Z(28.65)).L(X(16.5), Z(28.55)));
    線(p => p.M(X(14.1), Z(27.75)).L(X(16.4), Z(27.65)));
    // 乚曲（收上挑）
    出(p => p.M(X(14.2), Z(29.3)).C(X(14.0), Z(30.5), X(14.7), Z(31.2), X(16.2), Z(31.1))
        .C(X(16.6), Z(31.0), X(16.8), Z(30.6), X(16.7), Z(30.2)));
    // 右月柱
    線(p => p.M(X(17.0), Z(26.45)).L(X(16.95), Z(30.4)));
    線(p => p.M(X(17.0), Z(26.5)).L(X(17.9), Z(26.4)).L(X(17.85), Z(30.2)));
};
